const query = $json.query || {};

const clusters = {
  clab: { testId: '7719616' },
  klab: { testId: '7719618' },
  emerald: { testId: '7719620' },
  gold: { testId: '7719621' },
  golddr: { testId: '7719622' },
  silver: { testId: '7719640' },
};

const testIdToCluster = Object.fromEntries(Object.entries(clusters).map(([cluster, cfg]) => [cfg.testId, cluster]));

let cluster = query.cluster ? String(query.cluster).toLowerCase() : '';
if (!cluster && query.test_id && testIdToCluster[String(query.test_id)]) {
  cluster = testIdToCluster[String(query.test_id)];
}
if (!clusters[cluster]) cluster = 'silver';

let days = parseInt(String(query.days || '30'), 10);
if (!Number.isFinite(days) || days < 1) days = 30;
if (days > 30) days = 30;

let bucketHours = parseInt(String(query.bucket_hours || '1'), 10);
if (!Number.isFinite(bucketHours) || bucketHours < 1) bucketHours = 1;
if (bucketHours > 24) bucketHours = 24;

const rollingDays = 30;
const rollingSeconds = rollingDays * 24 * 60 * 60;
const safeCluster = cluster.replace(/'/g, "''");
const sql = [
  'WITH params AS (',
  "  SELECT now() AS end_ts, now() - interval '" + days + " days' AS start_ts, interval '" + bucketHours + " hours' AS step, " + rollingSeconds + '::numeric AS rolling_seconds',
  '), points AS (',
  '  SELECT generate_series(date_trunc(\'hour\', start_ts), end_ts, step) AS bucket_ts, rolling_seconds',
  '  FROM params',
  '), uptime AS (',
  '  SELECT',
  '    p.bucket_ts,',
  '    COALESCE(SUM(EXTRACT(EPOCH FROM (LEAST(d.ended_at, p.bucket_ts) - GREATEST(d.started_at, p.bucket_ts - interval \'30 days\')))), 0)::numeric AS down_seconds,',
  '    p.rolling_seconds',
  '  FROM points p',
  '  LEFT JOIN public.statuscake_downtime_periods d',
  "    ON d.cluster = '" + safeCluster + "'",
  '   AND d.is_valid = true',
  '   AND d.started_at < p.bucket_ts',
  '   AND d.ended_at > p.bucket_ts - interval \'30 days\'',
  '  GROUP BY p.bucket_ts, p.rolling_seconds',
  ')',
  'SELECT',
  '  bucket_ts,',
  '  GREATEST(0, LEAST(100, ROUND((100 * (1 - (down_seconds / NULLIF(rolling_seconds, 0))))::numeric, 4))) AS uptime_percentage',
  'FROM uptime',
  'ORDER BY bucket_ts;'
].join('\n');

return [{ json: { cluster, testId: clusters[cluster].testId, days, bucketHours, rollingDays, sql } }];

const rows = $input.all().filter((item) => item.json && item.json.bucket_ts !== undefined);

const data = rows.map((item) => {
  const rawTs = item.json.bucket_ts;
  const timestamp = rawTs instanceof Date ? rawTs.toISOString() : new Date(rawTs).toISOString();

  return {
    timestamp,
    value: Number(item.json.uptime_percentage),
  };
});

return [{ json: { data } }];

